boolean-from-string:
fn boolean_from_string(s: &str) -> bool {
    match s.to_lowercase().as_str() {
        "true" => true,
        "false" => false,
        _ => false,
    }
}

string-substring:
fn string_substring(a: &str, start: usize, length: usize) -> &str {
    let end = start + length;
    &a[start..end]
}

rfc822Name-equal:
fn rfc822_name_equal(a: &str, b: &str) -> bool {
    if let (Some((local_a, domain_a)), Some((local_b, domain_b))) = (a.split_once('@'), b.split_once('@')) {
        local_a == local_b && domain_a.eq_ignore_ascii_case(domain_b)
    } else {
        false
    }
}

hexBinary-equal:
fn hex_binary_equal(a: &str, b: &str) -> bool {
    let decode = |s: &str| hex::decode(s).ok();
    match (decode(a), decode(b)) {
        (Some(bytes_a), Some(bytes_b)) => bytes_a == bytes_b,
        _ => false,
    }
}

base64Binary-equal:
fn base64_binary_equal(a: &str, b: &str) -> bool {
    let decode = |s: &str| base64::decode(s).ok();
    match (decode(a), decode(b)) {
        (Some(bytes_a), Some(bytes_b)) => bytes_a == bytes_b,
        _ => false,
    }
}

